{
  "project": "mms-fractal-planner",
  "version": "1.0.0-rewrite",
  "description": "High-Performance Train Maintenance Planner (PixiJS + SoA)",
  "stack": {
    "framework": "Vite",
    "ui": ["React 19", "MUI v7"],
    "rendering": "PixiJS v8",
    "state": ["Zustand (UI)", "Zustand Vanilla (Transient)", "TanStack Query"],
    "language": "TypeScript 5.x (Strict)",
    "testing": ["Vitest", "Playwright", "Playwright MCP"],
    "architecture": "Data-Oriented Design (SoA)"
  },
  "phases": {
    "setup-refactor": [
      { "id": "refactor-001", "name": "Remove Astro & Redux dependencies", "status": "done" },
      { "id": "refactor-002", "name": "Install TanStack Query & seedrandom", "status": "done" },
      { "id": "refactor-003", "name": "Configure Vite SPA mode", "status": "done" }
    ],
    "core-engine": [
      { "id": "engine-001", "name": "Implement SoA Data Structures (TypedArrays)", "status": "done" },
      { "id": "engine-002", "name": "Deterministic Mock Generator (Seeded)", "status": "done" },
      { "id": "engine-003", "name": "Virtual Scroller Logic (Physics/Inertia)", "status": "done" },
      { "id": "engine-004", "name": "Coordinate System Transformer (Time <-> Pixels)", "status": "done" }
    ],
    "rendering-layers": [
      { "id": "render-001", "name": "PixiJS Stage & Context Integration", "status": "done" },
      { "id": "render-002", "name": "LOD 0: Heatmap Fragment Shader", "status": "done" },
      { "id": "render-003", "name": "LOD 1: Instanced Mesh for Bars", "status": "done" },
      { "id": "render-004", "name": "LOD 2: Capsule Sprites & Text", "status": "pending" },
      { "id": "render-005", "name": "Hysteresis Zoom Logic", "status": "pending" }
    ],
    "interaction": [
      { "id": "interact-001", "name": "Transient Drag-and-Drop Controller", "status": "pending" },
      { "id": "interact-002", "name": "Collision Detection (Interval Tree)", "status": "pending" },
      { "id": "interact-003", "name": "React Overlays (Sidebar/Tooltip)", "status": "pending" }
    ],
    "testing-automation": [
      { "id": "test-001", "name": "Configure Playwright MCP for Claude Code visual testing", "status": "pending" },
      { "id": "test-002", "name": "Create Harness visual verification protocol", "status": "pending" },
      { "id": "test-003", "name": "Integrate screenshot validation in development workflow", "status": "pending" }
    ]
  }
}

